import 'dart:convert';\n\n/// Test pour vérifier le calcul des bénéfices avec coûts réels\nvoid main() {\n  print('🧪 Test du calcul des bénéfices avec coûts réels');\n  print('=' * 60);\n\n  // Test 1: Calcul avec coûts réels\n  testRealCostCalculation();\n  \n  // Test 2: Comparaison estimation vs réel\n  testEstimationVsReal();\n  \n  // Test 3: Gestion des produits sans prix d'achat\n  testMissingCostHandling();\n  \n  // Test 4: Calcul des marges\n  testMarginCalculation();\n\n  print('\\n✅ Tous les tests de calcul des bénéfices sont passés !');\n  print('🎯 Les bénéfices sont maintenant calculés avec les coûts réels !');\n}\n\nvoid testRealCostCalculation() {\n  print('\\n📋 Test 1: Calcul avec coûts réels');\n  \n  // Données de test avec coûts réels\n  final salesData = [\n    {\n      'id': 1,\n      'numeroVente': 'V001',\n      'montantTotal': 15000.0,\n      'items': [\n        {\n          'id': 1,\n          'produitId': 101,\n          'quantite': 2,\n          'prixUnitaire': 5000.0,\n          'produit': {\n            'id': 101,\n            'nom': 'Produit A',\n            'reference': 'PA001',\n            'prixAchat': 3000.0 // Coût réel\n          }\n        },\n        {\n          'id': 2,\n          'produitId': 102,\n          'quantite': 1,\n          'prixUnitaire': 5000.0,\n          'produit': {\n            'id': 102,\n            'nom': 'Produit B',\n            'reference': 'PB001',\n            'prixAchat': 2000.0 // Coût réel\n          }\n        }\n      ]\n    }\n  ];\n\n  try {\n    final sales = salesData.map((data) => Sale.fromJson(data)).toList();\n    \n    // Calculer le coût réel des marchandises vendues\n    double totalCostOfGoodsSold = 0.0;\n    double totalRevenue = 0.0;\n    \n    for (final sale in sales) {\n      totalRevenue += sale.montantTotal;\n      \n      if (sale.items != null && sale.items!.isNotEmpty) {\n        for (final item in sale.items!) {\n          final quantity = item.quantite;\n          final prixAchat = item.produit?.prixAchat ?? (item.prixUnitaire * 0.6);\n          \n          totalCostOfGoodsSold += quantity * prixAchat;\n        }\n      }\n    }\n    \n    final grossProfit = totalRevenue - totalCostOfGoodsSold;\n    final grossMargin = totalRevenue > 0 ? (grossProfit / totalRevenue * 100) : 0.0;\n    \n    print('  ✅ Calcul avec coûts réels réussi');\n    print('  📊 Chiffre d\\'affaires: ${totalRevenue.toStringAsFixed(0)} FCFA');\n    print('  📊 Coût réel des marchandises: ${totalCostOfGoodsSold.toStringAsFixed(0)} FCFA');\n    print('  📊 Marge brute réelle: ${grossProfit.toStringAsFixed(0)} FCFA');\n    print('  📊 Taux de marge brute: ${grossMargin.toStringAsFixed(1)}%');\n    \n    // Vérifications\n    assert(totalRevenue == 15000.0, 'Chiffre d\\'affaires incorrect');\n    assert(totalCostOfGoodsSold == 8000.0, 'Coût des marchandises incorrect'); // (2*3000) + (1*2000)\n    assert(grossProfit == 7000.0, 'Marge brute incorrecte');\n    assert(grossMargin.round() == 47, 'Taux de marge incorrect'); // 7000/15000 * 100 = 46.67%\n    \n  } catch (e) {\n    print('  ❌ Erreur: $e');\n    throw Exception('Test calcul avec coûts réels échoué');\n  }\n}\n\nvoid testEstimationVsReal() {\n  print('\\n📋 Test 2: Comparaison estimation vs réel');\n  \n  final totalRevenue = 100000.0;\n  final realCostOfGoodsSold = 45000.0; // Coût réel\n  final estimatedCostOfGoodsSold = totalRevenue * 0.6; // 60000 (estimation)\n  final operatingExpenses = 20000.0;\n  \n  // Calcul avec estimation (méthode actuelle)\n  final estimatedGrossProfit = totalRevenue - estimatedCostOfGoodsSold;\n  final estimatedNetProfit = estimatedGrossProfit - operatingExpenses;\n  final estimatedProfitMargin = (estimatedNetProfit / totalRevenue) * 100;\n  \n  // Calcul avec coûts réels (nouvelle méthode)\n  final realGrossProfit = totalRevenue - realCostOfGoodsSold;\n  final realNetProfit = realGrossProfit - operatingExpenses;\n  final realProfitMargin = (realNetProfit / totalRevenue) * 100;\n  \n  try {\n    print('  📊 ESTIMATION (60%):');\n    print('    - Coût estimé: ${estimatedCostOfGoodsSold.toStringAsFixed(0)} FCFA');\n    print('    - Marge brute: ${estimatedGrossProfit.toStringAsFixed(0)} FCFA');\n    print('    - Bénéfice net: ${estimatedNetProfit.toStringAsFixed(0)} FCFA');\n    print('    - Marge bénéficiaire: ${estimatedProfitMargin.toStringAsFixed(1)}%');\n    \n    print('  📊 COÛTS RÉELS:');\n    print('    - Coût réel: ${realCostOfGoodsSold.toStringAsFixed(0)} FCFA');\n    print('    - Marge brute: ${realGrossProfit.toStringAsFixed(0)} FCFA');\n    print('    - Bénéfice net: ${realNetProfit.toStringAsFixed(0)} FCFA');\n    print('    - Marge bénéficiaire: ${realProfitMargin.toStringAsFixed(1)}%');\n    \n    final profitDifference = realNetProfit - estimatedNetProfit;\n    final marginDifference = realProfitMargin - estimatedProfitMargin;\n    \n    print('  🔍 DIFFÉRENCE:');\n    print('    - Différence de bénéfice: ${profitDifference.toStringAsFixed(0)} FCFA');\n    print('    - Différence de marge: ${marginDifference.toStringAsFixed(1)}%');\n    print('    - Impact: ${profitDifference > 0 ? '✅ Sous-estimation' : '❌ Sur-estimation'} du bénéfice');\n    \n    // Dans cet exemple, le coût réel (45%) est inférieur à l'estimation (60%)\n    // Donc le bénéfice réel devrait être supérieur à l'estimation\n    assert(realNetProfit > estimatedNetProfit, 'Le bénéfice réel devrait être supérieur');\n    assert(profitDifference == 15000.0, 'Différence de bénéfice incorrecte');\n    \n  } catch (e) {\n    print('  ❌ Erreur: $e');\n    throw Exception('Test comparaison estimation vs réel échoué');\n  }\n}\n\nvoid testMissingCostHandling() {\n  print('\\n📋 Test 3: Gestion des produits sans prix d\\'achat');\n  \n  // Données avec certains produits sans prix d'achat\n  final salesData = [\n    {\n      'id': 1,\n      'numeroVente': 'V001',\n      'montantTotal': 10000.0,\n      'items': [\n        {\n          'id': 1,\n          'produitId': 101,\n          'quantite': 1,\n          'prixUnitaire': 5000.0,\n          'produit': {\n            'id': 101,\n            'nom': 'Produit avec coût',\n            'reference': 'PA001',\n            'prixAchat': 3000.0 // Coût réel disponible\n          }\n        },\n        {\n          'id': 2,\n          'produitId': 102,\n          'quantite': 1,\n          'prixUnitaire': 5000.0,\n          'produit': {\n            'id': 102,\n            'nom': 'Produit sans coût',\n            'reference': 'PB001'\n            // Pas de prixAchat\n          }\n        }\n      ]\n    }\n  ];\n\n  try {\n    final sales = salesData.map((data) => Sale.fromJson(data)).toList();\n    \n    double totalCostOfGoodsSold = 0.0;\n    int itemsWithRealCost = 0;\n    int itemsWithEstimatedCost = 0;\n    \n    for (final sale in sales) {\n      if (sale.items != null && sale.items!.isNotEmpty) {\n        for (final item in sale.items!) {\n          final quantity = item.quantite;\n          final prixUnitaire = item.prixUnitaire;\n          \n          double prixAchat;\n          if (item.produit?.prixAchat != null && item.produit!.prixAchat! > 0) {\n            prixAchat = item.produit!.prixAchat!;\n            itemsWithRealCost++;\n          } else {\n            prixAchat = prixUnitaire * 0.6; // Estimation fallback\n            itemsWithEstimatedCost++;\n          }\n          \n          totalCostOfGoodsSold += quantity * prixAchat;\n        }\n      }\n    }\n    \n    print('  ✅ Gestion des coûts manquants réussie');\n    print('  📊 Articles avec coût réel: $itemsWithRealCost');\n    print('  📊 Articles avec estimation: $itemsWithEstimatedCost');\n    print('  📊 Coût total calculé: ${totalCostOfGoodsSold.toStringAsFixed(0)} FCFA');\n    \n    // Vérifications\n    assert(itemsWithRealCost == 1, 'Nombre d\\'articles avec coût réel incorrect');\n    assert(itemsWithEstimatedCost == 1, 'Nombre d\\'articles avec estimation incorrect');\n    assert(totalCostOfGoodsSold == 6000.0, 'Coût total incorrect'); // 3000 + (5000*0.6)\n    \n  } catch (e) {\n    print('  ❌ Erreur: $e');\n    throw Exception('Test gestion des coûts manquants échoué');\n  }\n}\n\nvoid testMarginCalculation() {\n  print('\\n📋 Test 4: Calcul des marges');\n  \n  final testCases = [\n    {\n      'name': 'Marge élevée',\n      'revenue': 10000.0,\n      'cost': 4000.0,\n      'expenses': 2000.0,\n      'expectedGrossMargin': 60.0, // (10000-4000)/10000 * 100\n      'expectedNetMargin': 40.0,   // (10000-4000-2000)/10000 * 100\n    },\n    {\n      'name': 'Marge faible',\n      'revenue': 10000.0,\n      'cost': 8000.0,\n      'expenses': 1500.0,\n      'expectedGrossMargin': 20.0, // (10000-8000)/10000 * 100\n      'expectedNetMargin': 5.0,    // (10000-8000-1500)/10000 * 100\n    },\n    {\n      'name': 'Perte',\n      'revenue': 10000.0,\n      'cost': 7000.0,\n      'expenses': 4000.0,\n      'expectedGrossMargin': 30.0,  // (10000-7000)/10000 * 100\n      'expectedNetMargin': -10.0,   // (10000-7000-4000)/10000 * 100\n    }\n  ];\n\n  try {\n    for (final testCase in testCases) {\n      final revenue = testCase['revenue'] as double;\n      final cost = testCase['cost'] as double;\n      final expenses = testCase['expenses'] as double;\n      \n      final grossProfit = revenue - cost;\n      final netProfit = grossProfit - expenses;\n      final grossMargin = revenue > 0 ? (grossProfit / revenue * 100) : 0.0;\n      final netMargin = revenue > 0 ? (netProfit / revenue * 100) : 0.0;\n      \n      print('  📊 ${testCase['name']}:');\n      print('    - Marge brute: ${grossMargin.toStringAsFixed(1)}% (attendu: ${testCase['expectedGrossMargin']}%)');\n      print('    - Marge nette: ${netMargin.toStringAsFixed(1)}% (attendu: ${testCase['expectedNetMargin']}%)');\n      \n      // Vérifications avec tolérance\n      final grossMarginExpected = testCase['expectedGrossMargin'] as double;\n      final netMarginExpected = testCase['expectedNetMargin'] as double;\n      \n      assert((grossMargin - grossMarginExpected).abs() < 0.1, 'Marge brute incorrecte pour ${testCase['name']}');\n      assert((netMargin - netMarginExpected).abs() < 0.1, 'Marge nette incorrecte pour ${testCase['name']}');\n    }\n    \n    print('  ✅ Tous les calculs de marges sont corrects');\n    \n  } catch (e) {\n    print('  ❌ Erreur: $e');\n    throw Exception('Test calcul des marges échoué');\n  }\n}\n\n// Classes de test simplifiées\nclass Sale {\n  final int id;\n  final String numeroVente;\n  final double montantTotal;\n  final List<SaleDetail>? items;\n\n  Sale({\n    required this.id,\n    required this.numeroVente,\n    required this.montantTotal,\n    this.items,\n  });\n\n  factory Sale.fromJson(Map<String, dynamic> json) {\n    return Sale(\n      id: json['id'] ?? 0,\n      numeroVente: json['numeroVente'] ?? '',\n      montantTotal: (json['montantTotal'] ?? 0.0).toDouble(),\n      items: json['items'] != null\n          ? (json['items'] as List).map((item) => SaleDetail.fromJson(item)).toList()\n          : null,\n    );\n  }\n}\n\nclass SaleDetail {\n  final int id;\n  final int produitId;\n  final int quantite;\n  final double prixUnitaire;\n  final ProductSummary? produit;\n\n  SaleDetail({\n    required this.id,\n    required this.produitId,\n    required this.quantite,\n    required this.prixUnitaire,\n    this.produit,\n  });\n\n  factory SaleDetail.fromJson(Map<String, dynamic> json) {\n    return SaleDetail(\n      id: json['id'] ?? 0,\n      produitId: json['produitId'] ?? 0,\n      quantite: json['quantite'] ?? 0,\n      prixUnitaire: (json['prixUnitaire'] ?? 0.0).toDouble(),\n      produit: json['produit'] != null\n          ? ProductSummary.fromJson(json['produit'])\n          : null,\n    );\n  }\n}\n\nclass ProductSummary {\n  final int id;\n  final String nom;\n  final String reference;\n  final double? prixAchat;\n\n  ProductSummary({\n    required this.id,\n    required this.nom,\n    required this.reference,\n    this.prixAchat,\n  });\n\n  factory ProductSummary.fromJson(Map<String, dynamic> json) {\n    return ProductSummary(\n      id: json['id'] ?? 0,\n      nom: json['nom'] ?? '',\n      reference: json['reference'] ?? '',\n      prixAchat: json['prixAchat']?.toDouble(),\n    );\n  }\n}\n"